def get_exercises_string():
    """Returns the library formatted as a string for the AI prompt."""
    result = "✅ EXERCISE LIBRARY (ONLY SELECT FROM THIS LIST):\n"
    for ex in EXERCISE_LIBRARY:
        result += f"- {ex['name']} (Muscle: {ex['muscle']}, Video: {ex['video']})\n"
    return result
